const checkpoints = [];

function datePart(iso){ return iso ? iso.substring(0,10) : ''; }
function timePart(iso){ return iso ? iso.substring(11,16) : ''; }

const sessions = JSON.parse(localStorage.getItem('group_class_sessions') || '[]');
const classTypes = JSON.parse(localStorage.getItem('group_class_types') || '[]');
const bookings = JSON.parse(localStorage.getItem('group_class_bookings') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
let baselineDateStr = null;
if (metadataRaw) {
  try {
    const m = JSON.parse(metadataRaw);
    if (m && m.baselineDate) baselineDateStr = m.baselineDate;
  } catch (e) {}
}
if (!baselineDateStr) {
  baselineDateStr = new Date().toISOString().substring(0,10);
}

// Compute upcoming weekend (Saturday and Sunday after baseline date)
const baseDate = new Date(baselineDateStr + 'T00:00:00Z');
const dayMs = 24*60*60*1000;
const dow = baseDate.getUTCDay(); // 0=Sun..6=Sat
const satDelta = (6 - dow + 7) % 7; // upcoming Saturday
const satDate = new Date(baseDate.getTime() + satDelta * dayMs);
const sunDate = new Date(satDate.getTime() + dayMs);
const weekendDates = [satDate.toISOString().substring(0,10), sunDate.toISOString().substring(0,10)];

// All qualifying sessions by criteria
const qualifyingSessions = sessions.filter(s => {
  const ct = classTypes.find(t => t.id === s.class_type_id);
  if (!ct) return false;
  if (ct.audience !== 'adult' || ct.level !== 'beginner') return false;
  if (!weekendDates.includes(datePart(s.start_datetime))) return false;
  if (timePart(s.start_datetime) < '17:00') return false;
  if (typeof s.price !== 'number' || s.price >= 35) return false;
  if (s.status !== 'scheduled') return false;
  return true;
});

let minPrice = null;
let cheapestSessionIds = [];
if (qualifyingSessions.length > 0) {
  minPrice = qualifyingSessions.reduce((min, s) => (min === null || s.price < min ? s.price : min), null);
  cheapestSessionIds = qualifyingSessions.filter(s => s.price === minPrice).map(s => s.id);
}

// Bookings for any qualifying session
const qualifyingBookings = bookings.filter(b => {
  if (b.status !== 'in_cart' && b.status !== 'confirmed') return false;
  return qualifyingSessions.some(s => s.id === b.class_session_id);
});

// Bookings specifically for the cheapest qualifying session(s)
const cheapestBookings = bookings.filter(b => {
  if (b.status !== 'in_cart' && b.status !== 'confirmed') return false;
  return cheapestSessionIds.includes(b.class_session_id);
});

// CP1 (0.5): User booked at least one class session that meets all weekend adult beginner, time, and price criteria
checkpoints.push({ passed: qualifyingBookings.length > 0, weight: 0.5 });

// CP2 (0.5): User booked one of the cheapest qualifying sessions among all options matching the criteria
checkpoints.push({ passed: cheapestSessionIds.length > 0 && cheapestBookings.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('membership_plans') || '[]');
const inquiries = JSON.parse(localStorage.getItem('membership_inquiries') || '[]');
let comparedIds = [];
const comparedRaw = localStorage.getItem('task2_comparedPlanIds');
if (comparedRaw) {
  try {
    const parsed = JSON.parse(comparedRaw);
    if (Array.isArray(parsed)) {
      comparedIds = parsed.map(id => String(id));
    }
  } catch (e) {}
}

// Qualifying plans: active and with >= 4 included group sessions per month
const qualifyingPlans = plans.filter(p => p.is_active && typeof p.included_group_sessions_per_month === 'number' && p.included_group_sessions_per_month >= 4);
const qualifyingPlanIds = qualifyingPlans.map(p => p.id);

// CP1 (0.30): User viewed detail pages for all qualifying plans (according to instrumentation)
const viewedAllQualifying = qualifyingPlanIds.length > 0 && qualifyingPlanIds.every(id => comparedIds.includes(id));
checkpoints.push({ passed: viewedAllQualifying, weight: 0.3 });

// Any inquiry submitted for a qualifying plan
const qualifyingInquiries = inquiries.filter(i => qualifyingPlanIds.includes(i.membership_plan_id));

// CP2 (0.30): User submitted at least one membership inquiry for a plan that includes >= 4 group sessions/month
const submittedQualifyingInquiry = qualifyingInquiries.length > 0;
checkpoints.push({ passed: submittedQualifyingInquiry, weight: 0.3 });

// Determine the cheapest qualifying plan by monthly_price
let cheapestPlan = null;
if (qualifyingPlans.length > 0) {
  cheapestPlan = qualifyingPlans.slice().sort((a, b) => {
    if (a.monthly_price === b.monthly_price) return 0;
    return a.monthly_price < b.monthly_price ? -1 : 1;
  })[0];
}

// CP3 (0.40): User submitted an inquiry specifically for the cheapest qualifying plan
let inquiredCheapest = false;
if (cheapestPlan) {
  inquiredCheapest = inquiries.some(i => i.membership_plan_id === cheapestPlan.id);
}
checkpoints.push({ passed: !!cheapestPlan && inquiredCheapest, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function datePart(iso){ return iso ? iso.substring(0,10) : ''; }
function timePart(iso){ return iso ? iso.substring(11,16) : ''; }
function durationMinutes(startIso, endIso){ if (!startIso || !endIso) return null; return (new Date(endIso) - new Date(startIso)) / 60000; }

const courts = JSON.parse(localStorage.getItem('courts') || '[]');
const reservations = JSON.parse(localStorage.getItem('court_reservations') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
let baselineDateStr = null;
if (metadataRaw) {
  try {
    const m = JSON.parse(metadataRaw);
    if (m && m.baselineDate) baselineDateStr = m.baselineDate;
  } catch (e) {}
}
if (!baselineDateStr) {
  baselineDateStr = new Date().toISOString().substring(0,10);
}

// Compute "next Wednesday" as the Wednesday in the following week after baseline
const baseDate = new Date(baselineDateStr + 'T00:00:00Z');
const dayMs = 24*60*60*1000;
const nextWeekSameDay = new Date(baseDate.getTime() + 7 * dayMs);
const targetDow = 3; // Wednesday
const offset = (targetDow - nextWeekSameDay.getUTCDay() + 7) % 7;
const targetDate = new Date(nextWeekSameDay.getTime() + offset * dayMs);
const targetDateStr = targetDate.toISOString().substring(0,10);

// Find reservations that match all criteria
const qualifyingReservations = reservations.filter(r => {
  if (r.status !== 'in_cart' && r.status !== 'confirmed') return false;
  if (datePart(r.start_datetime) !== targetDateStr) return false;
  if (timePart(r.start_datetime) !== '19:00') return false;
  if (durationMinutes(r.start_datetime, r.end_datetime) !== 90) return false;
  if (r.play_format !== 'doubles') return false;
  if (!Array.isArray(r.player_names) || r.player_names.length < 4) return false;
  const court = courts.find(c => c.id === r.court_id);
  if (!court) return false;
  if (court.surface !== 'hard' || court.location_type !== 'indoor') return false;
  return true;
});

// CP1 (0.60): User created at least one court reservation matching indoor hard, next Wednesday 7:00–8:30 PM, doubles with 4+ players
const hasQualifyingReservation = qualifyingReservations.length > 0;
checkpoints.push({ passed: hasQualifyingReservation, weight: 0.6 });

// CP2 (0.40): That qualifying reservation is present as an active court_reservation cart item
const qualifyingReservationIds = qualifyingReservations.map(r => r.id);
const hasQualifyingCartItem = cartItems.some(ci => ci.status === 'active' && ci.item_type === 'court_reservation' && qualifyingReservationIds.includes(ci.reference_id));
checkpoints.push({ passed: hasQualifyingReservation && hasQualifyingCartItem, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function timePart(iso){ return iso ? iso.substring(11,16) : ''; }

const slots = JSON.parse(localStorage.getItem('private_lesson_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('private_lesson_bookings') || '[]');
const coaches = JSON.parse(localStorage.getItem('coaches') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
let baselineISO = null;
if (metadataRaw) {
  try {
    const m = JSON.parse(metadataRaw);
    if (m && m.baselineDate) baselineISO = m.baselineDate + 'T00:00:00Z';
  } catch (e) {}
}
if (!baselineISO) {
  baselineISO = new Date().toISOString();
}
const baselineDate = new Date(baselineISO);

// All candidate slots that meet constraints
const candidateSlots = slots.filter(slot => {
  if (slot.status !== 'available') return false;
  const start = new Date(slot.start_datetime);
  if (start <= baselineDate) return false;
  const dow = start.getUTCDay(); // 0=Sun..6=Sat
  if (dow === 0 || dow === 6) return false; // weekdays only
  if (timePart(slot.start_datetime) < '16:00') return false;
  const coach = coaches.find(c => c.id === slot.coach_id);
  if (!coach) return false;
  if (typeof coach.rating !== 'number' || coach.rating < 4.5) return false;
  const specs = Array.isArray(coach.specialties) ? coach.specialties.map(s => String(s).toLowerCase()) : [];
  if (!specs.includes('backhand')) return false;
  return true;
});

// Earliest such slot
let earliestSlot = null;
if (candidateSlots.length > 0) {
  earliestSlot = candidateSlots.slice().sort((a, b) => {
    if (a.start_datetime === b.start_datetime) return 0;
    return a.start_datetime < b.start_datetime ? -1 : 1;
  })[0];
}

// Bookings that satisfy the lesson constraints (weekday, 4pm+, coach 4.5+, backhand, 60 minutes)
const qualifyingBookings = bookings.filter(b => {
  if (b.status !== 'in_cart' && b.status !== 'confirmed') return false;
  const slot = slots.find(s => s.id === b.lesson_slot_id);
  if (!slot) return false;
  const start = new Date(slot.start_datetime);
  const dow = start.getUTCDay();
  if (dow === 0 || dow === 6) return false;
  if (timePart(slot.start_datetime) < '16:00') return false;
  const coach = coaches.find(c => c.id === slot.coach_id);
  if (!coach) return false;
  if (typeof coach.rating !== 'number' || coach.rating < 4.5) return false;
  const specs = Array.isArray(coach.specialties) ? coach.specialties.map(s => String(s).toLowerCase()) : [];
  if (!specs.includes('backhand')) return false;
  if (b.duration_minutes !== 60) return false;
  return true;
});

// CP1 (0.50): User has booked at least one private lesson that meets all coach, rating, weekday, time, and duration constraints
const hasQualifyingBooking = qualifyingBookings.length > 0;
checkpoints.push({ passed: hasQualifyingBooking, weight: 0.5 });

// CP2 (0.50): Among all qualifying slots, the user booked the earliest available one
let bookedEarliest = false;
if (earliestSlot && qualifyingBookings.length > 0) {
  bookedEarliest = qualifyingBookings.some(b => b.lesson_slot_id === earliestSlot.id);
}
checkpoints.push({ passed: !!earliestSlot && bookedEarliest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const camps = JSON.parse(localStorage.getItem('camps') || '[]');
const campSessions = JSON.parse(localStorage.getItem('camp_sessions') || '[]');
const enrollments = JSON.parse(localStorage.getItem('camp_enrollments') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const childAge = 10;

function getMonthYear(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  return { month: d.getUTCMonth() + 1, year: d.getUTCFullYear() };
}

// Camp sessions that meet July, morning half-day, price range, and age suitability
const qualifyingSessions = campSessions.filter(cs => {
  const camp = camps.find(c => c.id === cs.camp_id);
  if (!camp || !camp.is_active) return false;
  const my = getMonthYear(cs.start_date);
  if (!my || my.month !== 7) return false; // July
  if (cs.session_type !== 'half_day_am') return false;
  if (typeof cs.price !== 'number' || cs.price < 280 || cs.price > 300) return false;
  if (typeof camp.age_min === 'number' && childAge < camp.age_min) return false;
  if (typeof camp.age_max === 'number' && childAge > camp.age_max) return false;
  return true;
});

const qualifyingSessionIds = qualifyingSessions.map(cs => cs.id);

// Enrollments that match child age and a qualifying session, with in_cart status
const qualifyingEnrollments = enrollments.filter(e => {
  if (e.status !== 'in_cart') return false;
  if (e.child_age !== childAge) return false;
  if (!qualifyingSessionIds.includes(e.camp_session_id)) return false;
  return true;
});

// CP1 (0.60): User created at least one camp enrollment for a 10-year-old in a qualifying July morning half-day session priced $280–$300
const hasQualifyingEnrollment = qualifyingEnrollments.length > 0;
checkpoints.push({ passed: hasQualifyingEnrollment, weight: 0.6 });

// CP2 (0.40): That qualifying enrollment appears as an active camp_enrollment cart item
const qualifyingEnrollmentIds = qualifyingEnrollments.map(e => e.id);
const hasQualifyingCartItem = cartItems.some(ci => ci.status === 'active' && ci.item_type === 'camp_enrollment' && qualifyingEnrollmentIds.includes(ci.reference_id));
checkpoints.push({ passed: hasQualifyingEnrollment && hasQualifyingCartItem, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function datePart(iso){ return iso ? iso.substring(0,10) : ''; }

const classTypes = JSON.parse(localStorage.getItem('group_class_types') || '[]');
const sessions = JSON.parse(localStorage.getItem('group_class_sessions') || '[]');
const bookings = JSON.parse(localStorage.getItem('group_class_bookings') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
let baselineDateStr = null;
if (metadataRaw) {
  try {
    const m = JSON.parse(metadataRaw);
    if (m && m.baselineDate) baselineDateStr = m.baselineDate;
  } catch (e) {}
}
if (!baselineDateStr) {
  baselineDateStr = new Date().toISOString().substring(0,10);
}

// Compute upcoming week range: Monday–Sunday of the next week after baseline
const baseDate = new Date(baselineDateStr + 'T00:00:00Z');
const dayMs = 24*60*60*1000;
const baseDow = baseDate.getUTCDay(); // 0=Sun..6=Sat
const nextMondayOffset = (1 - baseDow + 7) % 7; // next Monday
const upcomingMonday = new Date(baseDate.getTime() + nextMondayOffset * dayMs);
const weekStartStr = upcomingMonday.toISOString().substring(0,10);
const weekEnd = new Date(upcomingMonday.getTime() + 6 * dayMs);
const weekEndStr = weekEnd.toISOString().substring(0,10);

// Maps for joins
const bookingById = {};
bookings.forEach(b => { bookingById[b.id] = b; });
const sessionById = {};
sessions.forEach(s => { sessionById[s.id] = s; });
const typeById = {};
classTypes.forEach(ct => { typeById[ct.id] = ct; });

// Active group class cart items enriched with booking, session, and class type
const bookingCartItems = cartItems.filter(ci => ci.status === 'active' && ci.item_type === 'group_class_booking');
const enriched = bookingCartItems.map(ci => {
  const booking = bookingById[ci.reference_id];
  const session = booking ? sessionById[booking.class_session_id] : null;
  const ct = session ? typeById[session.class_type_id] : null;
  return { cartItem: ci, booking, session, classType: ct };
}).filter(x => x.booking && x.session && x.classType);

// Filter to adult intermediate sessions in the upcoming week
const candidateItems = enriched.filter(x => {
  const ct = x.classType;
  if (ct.audience !== 'adult' || ct.level !== 'intermediate') return false;
  const d = datePart(x.session.start_datetime);
  if (d < weekStartStr || d > weekEndStr) return false;
  return true;
});

const cardioItems = candidateItems.filter(x => x.classType.focus === 'cardio');
const strategyItems = candidateItems.filter(x => x.classType.focus === 'strategy');
const matchPlayItems = candidateItems.filter(x => x.classType.focus === 'match_play');

function havePairDifferentDays(arr1, arr2) {
  for (const a of arr1) {
    for (const b of arr2) {
      if (!a.session || !b.session) continue;
      const da = datePart(a.session.start_datetime);
      const db = datePart(b.session.start_datetime);
      if (da !== db) return true;
    }
  }
  return false;
}

// Examine all triples for distinct days and budget
let tripleExists = false;
let tripleWithinBudget = false;
for (const c of cardioItems) {
  for (const s of strategyItems) {
    for (const m of matchPlayItems) {
      if (!c.session || !s.session || !m.session) continue;
      const dc = datePart(c.session.start_datetime);
      const ds = datePart(s.session.start_datetime);
      const dm = datePart(m.session.start_datetime);
      if (dc === ds || dc === dm || ds === dm) continue; // need three different days
      tripleExists = true;
      const totalPrice = (c.cartItem.price || 0) + (s.cartItem.price || 0) + (m.cartItem.price || 0);
      if (totalPrice < 120) {
        tripleWithinBudget = true;
      }
    }
  }
}

// CP1 (0.30): At least one cardio + strategy combination on different days in the upcoming week
const pairCardioStrategy = havePairDifferentDays(cardioItems, strategyItems);
checkpoints.push({ passed: pairCardioStrategy, weight: 0.3 });

// CP2 (0.30): There exists a cardio + strategy + match play triple on three different days in the upcoming week
checkpoints.push({ passed: tripleExists, weight: 0.3 });

// CP3 (0.40): At least one such triple of days has a combined cart price under $120
checkpoints.push({ passed: tripleWithinBudget, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const tournaments = JSON.parse(localStorage.getItem('tournaments') || '[]');
const events = JSON.parse(localStorage.getItem('tournament_events') || '[]');
const regs = JSON.parse(localStorage.getItem('tournament_registrations') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
let baselineDate = null;
if (metadataRaw) {
  try {
    const m = JSON.parse(metadataRaw);
    if (m && m.baselineDate) baselineDate = new Date(m.baselineDate + 'T00:00:00Z');
  } catch (e) {}
}
if (!baselineDate) {
  baselineDate = new Date();
}

const baseMonth = baselineDate.getUTCMonth(); // 0-based
const baseYear = baselineDate.getUTCFullYear();
let nextMonth = baseMonth + 1;
let yearForNextMonth = baseYear;
if (nextMonth > 11) {
  nextMonth = 0;
  yearForNextMonth += 1;
}

function getMonthYear(dateStr) {
  const d = new Date(dateStr);
  return { month: d.getUTCMonth(), year: d.getUTCFullYear() }; // month 0-11
}

// Tournaments next month with a singles 3.0–3.5 event
const candidateTournaments = tournaments.filter(t => {
  if (!t.start_date) return false;
  if (t.status && t.status !== 'upcoming') return false;
  const my = getMonthYear(t.start_date);
  if (my.year !== yearForNextMonth || my.month !== nextMonth) return false;
  const eventsForT = events.filter(e => e.tournament_id === t.id);
  return eventsForT.some(e => e.event_type === 'singles' && e.rating_min === 3.0 && e.rating_max === 3.5);
});

candidateTournaments.sort((a, b) => {
  if (a.start_date === b.start_date) return 0;
  return a.start_date < b.start_date ? -1 : 1;
});

const targetTournament = candidateTournaments[0] || null;
let targetEvent = null;
if (targetTournament) {
  const eventsForT = events.filter(e => e.tournament_id === targetTournament.id);
  const singlesEvents = eventsForT.filter(e => e.event_type === 'singles' && e.rating_min === 3.0 && e.rating_max === 3.5);
  if (singlesEvents.length > 0) {
    targetEvent = singlesEvents[0];
  }
}

let qualifyingRegs = [];
if (targetEvent) {
  // Treat new registrations (for this task) as in_cart to avoid counting pre-existing confirmed ones
  qualifyingRegs = regs.filter(r => r.tournament_event_id === targetEvent.id && r.status === 'in_cart');
}

// CP1 (0.60): User has an in-cart registration for the singles 3.0–3.5 event at the earliest qualifying tournament next month
const hasQualifyingReg = qualifyingRegs.length > 0;
checkpoints.push({ passed: !!targetEvent && hasQualifyingReg, weight: 0.6 });

// CP2 (0.40): That registration is present as an active tournament_registration cart item
const qualifyingRegIds = qualifyingRegs.map(r => r.id);
const hasQualifyingCartItem = cartItems.some(ci => ci.status === 'active' && ci.item_type === 'tournament_registration' && qualifyingRegIds.includes(ci.reference_id));
checkpoints.push({ passed: !!targetEvent && hasQualifyingReg && hasQualifyingCartItem, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

const readingListIds = readingLists.map(l => l.id);
if (readingListIds.length === 0) {
  // No reading list means no qualifying saves
  checkpoints.push({ passed: false, weight: 0.5 });
  checkoints.push({ passed: false, weight: 0.5 });
  return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
}

const savedArticleIds = items.filter(it => readingListIds.includes(it.reading_list_id)).map(it => it.article_id);

function hasTag(article, tag) {
  return Array.isArray(article.tags) && article.tags.some(t => String(t).toLowerCase() === tag);
}

// Featured serve-technique articles
const serveCandidates = articles.filter(a => a.is_featured && a.category === 'serve' && hasTag(a, 'serve technique'));
const serveCandidateIds = serveCandidates.map(a => a.id);

// Featured injury-prevention articles
const injuryCandidates = articles.filter(a => a.is_featured && hasTag(a, 'injury prevention'));
const injuryCandidateIds = injuryCandidates.map(a => a.id);

// CP1 (0.50): At least one featured serve-technique article saved to reading list
const hasServeArticle = savedArticleIds.some(id => serveCandidateIds.includes(id));
checkpoints.push({ passed: hasServeArticle, weight: 0.5 });

// CP2 (0.50): At least one featured injury-prevention article saved to reading list
const hasInjuryArticle = savedArticleIds.some(id => injuryCandidateIds.includes(id));
checkpoints.push({ passed: hasInjuryArticle, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
